code.C:
#include <stdio.h>
#include <string.h>

void generateSubsequences(char *str) {
    int n = strlen(str);
    for (int i = 0; i < (1 << n); i++) {
        for (int j = 0; j < n; j++) {
            if (i & (1 << j)) {
                printf("%c", str[j]);
            }
        }
        printf("\n");
    }
}

int main() {
    char str[100];
    printf("Enter a string: ");
    scanf("%s", str);
    generateSubsequences(str);
    return 0;
}

