#include <iostream>
#include <string>
using namespace std;

void generateSubsequences(string str) {
    int n = str.length();
    for (int i = 0; i < (1 << n); i++) {
        for (int j = 0; j < n; j++) {
            if (i & (1 << j)) {
                cout << str[j];
            }
        }
        cout << endl;
    }
}

int main() {
    string str;
    cout << "Enter a string: ";
    cin >> str;
    generateSubsequences(str);
    return 0;
}

code.Java:
import java.util.Scanner;
public class Main {
    public static void generateSubsequences(String str) {
        int n = str.length();
        for (int i = 0; i < (1 << n); i++) {
            for (int j = 0; j < n; j++) {
                if ((i & (1 << j)) != 0) {
                    System.out.print(str.charAt(j));
                }
            }
            System.out.println();
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String str = scanner.next();
        generateSubsequences(str);
    }
}

